CREATE OR REPLACE VIEW vw_workflows WITH (security_invoker = ON) AS
SELECT
  t.workflow_id,
  t.title,
  t.description,
  t.created,
  t.modified,
  t.identifier,
  t.workflow_steps
FROM workflows t;

CREATE OR REPLACE VIEW vw_workflow_steps WITH (security_invoker = ON) AS
SELECT
  t.workflow_step_id,
  t.label,
  t.sequence_position,
  t.requires_human_approval,
  t.is_step_of,
  t.assigned_role
FROM workflow_steps t;

CREATE OR REPLACE VIEW vw_roles WITH (security_invoker = ON) AS
SELECT
  t.role_id,
  t.label,
  t.comment,
  t.filled_by,
  t.workflow_steps
FROM roles t;

CREATE OR REPLACE VIEW vw_human_agents WITH (security_invoker = ON) AS
SELECT
  t.human_agent_id,
  t.name,
  t.mbox,
  t.roles
FROM human_agents t;

